# Delegates a query to the billingAgent agent.
# + query - The request to send to the billingAgent agent.
# + return - The response from the billingAgent agent.
@ai:AgentTool
isolated function billingAgentTool(ai:Context context, string query) returns BillingResponse|error {
    BillingResponse|error response = self.billingAgent.run(query, context = context);
    return response;
}
